import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

export default function Login() {
  const [email, setEmail] = useState('admin@crm.com');
  const [password, setPassword] = useState('password');
  const [error, setError] = useState('');
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    try {
      await login(email, password);
      navigate('/dashboard');
    } catch (err) {
      setError('Invalid email or password');
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h1 style={styles.title}>🏠 Real Estate CRM</h1>
        <p style={styles.subtitle}>Sign in to your account</p>
        {error && <div style={styles.error}>{error}</div>}
        <form onSubmit={handleSubmit}>
          <div style={styles.field}>
            <label style={styles.label}>Email</label>
            <input style={styles.input} type="email" value={email}
              onChange={e => setEmail(e.target.value)} required />
          </div>
          <div style={styles.field}>
            <label style={styles.label}>Password</label>
            <input style={styles.input} type="password" value={password}
              onChange={e => setPassword(e.target.value)} required />
          </div>
          <button type="submit" style={styles.button}>Login</button>
        </form>
        <p style={{textAlign:'center', marginTop:12, color:'#6b7280', fontSize:13}}>
          Default: admin@crm.com / admin123
        </p>
      </div>
    </div>
  );
}

const styles = {
  container: { minHeight:'100vh', display:'flex', alignItems:'center', justifyContent:'center', background:'#f3f4f6' },
  card: { background:'#fff', padding:'40px', borderRadius:'12px', width:'380px', boxShadow:'0 4px 20px rgba(0,0,0,0.1)' },
  title: { textAlign:'center', color:'#1d4ed8', marginBottom:'4px', fontSize:'24px' },
  subtitle: { textAlign:'center', color:'#6b7280', marginBottom:'24px', fontSize:'14px' },
  field: { marginBottom:'16px' },
  label: { display:'block', marginBottom:'6px', color:'#374151', fontSize:'14px', fontWeight:'500' },
  input: { width:'100%', padding:'10px 12px', border:'1px solid #d1d5db', borderRadius:'8px', fontSize:'14px', boxSizing:'border-box', outline:'none' },
  button: { width:'100%', padding:'12px', background:'#1d4ed8', color:'#fff', border:'none', borderRadius:'8px', fontSize:'16px', cursor:'pointer', fontWeight:'600' },
  error: { background:'#fee2e2', color:'#dc2626', padding:'10px', borderRadius:'8px', marginBottom:'16px', fontSize:'14px' }
};
